import { useEffect, useState } from "react";

import axios from "axios";

import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const [requests, setRequests] =
    useState([]);

  const [prices, setPrices] =
    useState({});


  // LOAD REQUESTS

  useEffect(() => {

    fetchRequests();

  }, []);


  const fetchRequests = async () => {

    const user =
      JSON.parse(localStorage.getItem("user"));

    try {

      const res = await axios.get(
        `http://localhost:5000/api/request/labour/${user._id}`
      );

      setRequests(res.data);

    } catch (err) {

      alert("Failed to load requests");
    }
  };


  // ACCEPT REQUEST

  const acceptRequest = async (id) => {

    try {

      await axios.put(
        `http://localhost:5000/api/request/accept/${id}`,
        {
          price: prices[id]
        }
      );

      fetchRequests();

    } catch (err) {

      alert("Failed");
    }
  };


  // REJECT REQUEST

  const rejectRequest = async (id) => {

    try {

      await axios.put(
        `http://localhost:5000/api/request/reject/${id}`
      );

      fetchRequests();

    } catch (err) {

      alert("Failed");
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <div style={styles.header}>

          <h1 style={styles.heading}>
            Work Requests
          </h1>

          <p style={styles.subtext}>
            Manage customer work requests
          </p>

        </div>

        {/* NO REQUESTS */}

        {requests.length === 0 && (

          <div style={styles.empty}>
            No Requests Found
          </div>

        )}

        {/* REQUESTS */}

        <div style={styles.grid}>

          {requests.map(req => (

            <div
              key={req._id}
              style={styles.card}
            >

              <h2 style={styles.customer}>
                {req.customerName}
              </h2>

              <p style={styles.info}>
                <strong>Work:</strong>{" "}
                {req.workType}
              </p>

              <p style={styles.info}>
                <strong>Date:</strong>{" "}
                {req.date}
              </p>

              <p style={styles.info}>
                <strong>Timings:</strong>{" "}
                {req.timings?.join(", ")}
              </p>

              {/* STATUS */}

              <div style={styles.statusBox}>

                {req.status === "Pending" && (

                  <span style={styles.pending}>
                    Pending
                  </span>

                )}

                {req.status === "Accepted" && (

                  <span style={styles.accepted}>
                    Accepted
                  </span>

                )}

                {req.status === "Rejected" && (

                  <span style={styles.rejected}>
                    Rejected
                  </span>

                )}

              </div>

              {/* PRICE */}

              {req.status === "Pending" && (

                <>

                  <input
                    type="number"
                    placeholder="Enter Price"
                    style={styles.input}
                    onChange={(e) =>
                      setPrices({
                        ...prices,
                        [req._id]:
                        e.target.value
                      })
                    }
                  />

                  <div style={styles.buttonRow}>

                    <button
                      style={styles.acceptBtn}
                      onClick={() =>
                        acceptRequest(req._id)
                      }
                    >
                      Accept
                    </button>

                    <button
                      style={styles.rejectBtn}
                      onClick={() =>
                        rejectRequest(req._id)
                      }
                    >
                      Reject
                    </button>

                  </div>

                </>

              )}

              {/* ACCEPTED PRICE */}

              {req.status === "Accepted" && (

                <p style={styles.price}>
                  Price: ₹ {req.labourPrice}
                </p>

              )}

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px 60px"
  },

  header: {
    marginBottom: "30px"
  },

  heading: {
    fontSize: "30px",
    marginBottom: "8px",
    color: "#111827"
  },

  subtext: {
    color: "#6b7280"
  },

  empty: {
    background: "white",
    padding: "30px",
    borderRadius: "14px",
    textAlign: "center",
    color: "#6b7280"
  },

  grid: {
    display: "grid",
    gridTemplateColumns:
      "repeat(auto-fit,minmax(320px,1fr))",
    gap: "22px"
  },

  card: {
    background: "white",
    borderRadius: "18px",
    padding: "24px",
    boxShadow:
      "0 4px 15px rgba(0,0,0,0.05)"
  },

  customer: {
    marginBottom: "18px",
    color: "#111827"
  },

  info: {
    marginBottom: "12px",
    color: "#374151",
    lineHeight: "24px"
  },

  statusBox: {
    marginTop: "15px",
    marginBottom: "18px"
  },

  pending: {
    background: "#fef3c7",
    color: "#b45309",
    padding: "8px 14px",
    borderRadius: "20px",
    fontSize: "13px"
  },

  accepted: {
    background: "#dcfce7",
    color: "#166534",
    padding: "8px 14px",
    borderRadius: "20px",
    fontSize: "13px"
  },

  rejected: {
    background: "#fee2e2",
    color: "#991b1b",
    padding: "8px 14px",
    borderRadius: "20px",
    fontSize: "13px"
  },

  input: {
    width: "100%",
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    marginBottom: "18px",
    boxSizing: "border-box"
  },

  buttonRow: {
    display: "flex",
    gap: "12px"
  },

  acceptBtn: {
    flex: 1,
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "13px",
    borderRadius: "10px",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    background: "#ef4444",
    color: "white",
    border: "none",
    padding: "13px",
    borderRadius: "10px",
    cursor: "pointer"
  },

  price: {
    marginTop: "15px",
    fontWeight: "bold",
    color: "#2563eb"
  }

};
